// Check monitoring rules
const sources = $input.all().map(i => i.json);
if (sources.length === 0) {
  return [{ json: { skip: true, reason: 'No active competitor sources' } }];
}

// Safe fetch rules:
// - Only fetch sites that have safe_fetch allowed
// - Respect 10-30 second delays
// - Do not bypass CAPTCHA
// - Do not login
// - Return manual_review_required if fetch fails or price not found

const allowed_platforms = ['gelendzhik.travel', 'travelandia.ru'];

const toProcess = sources.filter(s => {
  const platformAllowed = allowed_platforms.includes(s.source_platform);
  // Check if already checked today
  const lastChecked = s.last_checked_at ? new Date(s.last_checked_at) : null;
  const checkedToday = lastChecked && (new Date() - lastChecked) < 23 * 3600 * 1000;
  return platformAllowed && !checkedToday;
});

if (toProcess.length === 0) {
  return [{ json: { skip: true, reason: 'All sources checked recently or platform not allowed' } }];
}

return toProcess.map(s => ({ json: s }));

// ── SAFE FETCH PLACEHOLDER ───────────────────────────────────────────────
// This workflow is INACTIVE (C1.5 placeholder).
// When activated in C3:
// 1. Use HTTP Request node with custom User-Agent and delays
// 2. Parse price from page HTML using regex / CSS selectors
// 3. If price found → insert competitor_price_observation with method='safe_fetch'
// 4. If price NOT found or error → insert with availability_status='manual_review_required'
// 5. Always update competitor_sources.last_checked_at
//
// ToS compliance:
// - gelendzhik.travel: no robots.txt restriction found for this path (verify on activation)
// - travelandia.ru: verify robots.txt before activation
// - Add 10-30 sec random delay between requests
// - Use legitimate User-Agent (e.g. Mozilla/5.0)
// - Never bypass CAPTCHA
// - Never login to competitor sites
// - Max 1 request per site per day
//
// For now: write manual_review_required observations
const source = $input.first().json;
const today = new Date().toISOString().split('T')[0];
const nextMonth = new Date(Date.now() + 30 * 86400000).toISOString().split('T')[0];

return [{ json: {
  q_source_id: source.id,
  q_from: today,
  q_to: nextMonth,
  q_nights: 30,
  q_price: null,
  q_status: 'manual_review_required',
  q_method: 'safe_fetch',
  q_confidence: null,
  q_notes: `Auto-check placeholder (C1.5). Workflow inactive. Manual review required for: ${source.name} (${source.source_platform}).`
}}];
